function technicalDocSections() {
  return [
    { type: "title", text: "Pallet Check Tool - Technical Documentation" },
    { type: "body", text: "Maintenance guide for the standalone Pallet_Check_Tool.html file. This PDF is generated directly by the HTML file, so it remains available when the tool is shared without any additional folder or repository access." },
    { type: "h1", text: "1. Application purpose" },
    { type: "body", text: "The tool supports pallet verification after system data has been exported and pasted into the browser. It allows the operator to search a Pallet ID, scan SKU or EAN codes, track progress, detect wrong scans, identify accidental Container ID scans and store operational history locally." },
    { type: "h1", text: "2. File architecture" },
    { type: "body", text: "The application is intentionally built as one HTML file. The body contains the screen structure, the style block contains visual layout and overrides, and the script block contains import logic, state management, pallet search, EAN resolution, scan workflow, logs, exports and the documentation download." },
    { type: "h1", text: "3. State model" },
    { type: "body", text: "DEFAULT_STATE defines the initial runtime state. The most important fields are rows, batchCount, mapping, completedHistory, palletActivity, wrongScans, scanMode, manualScanEntry, manualPalletEntry, scanLock, soundEnabled, customEanMap and lastImportDate. Runtime state is stored in the state object and persisted through localStorage." },
    { type: "body", text: "currentView describes what is currently displayed. scanState controls the active pallet checking process, including requirements, scannedCounts, completionLogged, status and lastScannedSku. When changing scan behavior, update scanState carefully because it drives progress, row highlighting and completion." },
    { type: "h1", text: "4. Import pipeline" },
    { type: "body", text: "parseRawData(rawText) converts pasted tab-separated system data into normalized records with sku, qty, palletId and containerId. Column positions come from getColumnIndexes(), which converts user-facing 1-based column numbers from state.mapping into JavaScript indexes." },
    { type: "body", text: "appendBatch(rows, sourceLabel) validates parsed rows, removes duplicates, adds unique rows into state.rows, increases batchCount, updates lastImportDate, saves state and refreshes import counters. Duplicate detection is controlled by buildRowKey(row). Change buildRowKey if business rules for duplicate rows change." },
    { type: "h1", text: "5. Pallet search logic" },
    { type: "body", text: "searchPallet() is the main pallet lookup function. It reads the input, verifies that data exists, blocks accidental switching from an unfinished pallet, supports suffix search such as *1234, searches exact Pallet ID, checks Container ID matches and renders either a result table, a selection list or a clear warning." },
    { type: "body", text: "If a pallet is not found and hasImportedToday() returns false, the tool displays the daily import warning instead of logging a wrong scan. This prevents stale data from being treated as an operator error. todayKey() defines the date format used for this check." },
    { type: "h1", text: "6. Result table and row rendering" },
    { type: "body", text: "renderResults(rows, palletId, options) controls the visible result area. renderCurrentMeta(rows, palletId, labelText) calculates summary values. renderRowTable(rows) builds each SKU row, resolves display EAN and applies scan-progress classes. If table columns are changed, update both the HTML header and renderRowTable." },
    { type: "body", text: "Pallet ID and Container ID column widths are controlled with nth-child CSS selectors. If the order of columns changes, those selectors must also be updated. Row progress uses the CSS variable --scan-fill." },
    { type: "h1", text: "7. SKU and EAN scanning" },
    { type: "body", text: "startScanWorkflow(rows, palletId) prepares scan requirements for the active pallet. handleSkuScan() processes every scan: it normalizes input, resolves EAN to SKU, checks whether the SKU belongs to the active pallet, increments scanned counts, handles duplicates, plays sound, refreshes the table and completes the pallet when all requirements are met." },
    { type: "body", text: "resolveSkuOrEan(value) checks the active EAN map, a shortened EAN version and finally the raw value as SKU. If EAN recognition fails, inspect rebuildEanMaps(), stripEanPrefix() and the currently loaded customEanMap." },
    { type: "h1", text: "8. Completion modes" },
    { type: "body", text: "Complete by SKU requires one confirmation per unique SKU. Complete by Quantity requires confirmations equal to imported quantity. Adding another mode requires changes in the Advanced Tools select, DEFAULT_STATE.scanMode, startScanWorkflow(), evaluatePalletStatus(), updateScanInstructionAndProgress() and any history/export wording." },
    { type: "h1", text: "9. Logs, history and pagination" },
    { type: "body", text: "addWrongScan(type, value, details) stores operational exceptions in state.wrongScans. logCompletedPallet() stores completed pallet runs in state.completedHistory. Both lists are limited with slice(0, 100) and rendered through paginated views. ACTIVITY_PAGE_SIZE controls visible rows per page." },
    { type: "h1", text: "10. UI change points" },
    { type: "body", text: "For top navigation search side-tab-panel and tab-btn. For this documentation card search doc-download-card and doc-download-link. For the right-side status cards search meta-grid and meta-card. For lower utility panels search stacked-panels, wrongScanSection, completedHistorySection and advancedTools. For completion popup behavior search workflow-modal and showWorkflowModal()." },
    { type: "h1", text: "11. Messages, sound and focus" },
    { type: "body", text: "setStatus(message, tone) controls status messages. showWorkflowModal() controls workflow popups. beep(type) controls success, error and completion sounds. getActiveInput(), queueFocusActiveInput() and queueFocusSkuInput() keep scanner focus in the correct field. Manual modes intentionally reduce automatic focus behavior." },
    { type: "h1", text: "12. Safe change checklist" },
    { type: "body", text: "After every change: refresh with Ctrl+F5, Clear All, import a small batch, search an existing pallet, scan a valid SKU or EAN, scan an invalid code, check Wrong Scan Log, complete a pallet, check Completed Pallets History, refresh again and confirm data restored from localStorage. Finally, copy only the HTML file and confirm the PDF documentation download still works." }
  ];
}

function escapePdfText(value) {
  return String(value).replace(/\\/g, \"\\\\\").replace(/\(/g, \"\\(\").replace(/\)/g, \"\\)\");
}

function wrapPdfText(text, maxChars) {
  const words = String(text).split(/\s+/);
  const lines = [];
  let line = "";
  words.forEach((word) => {
    const next = line ? line + " " + word : word;
    if (next.length > maxChars && line) {
      lines.push(line);
      line = word;
    } else {
      line = next;
    }
  });
  if (line) lines.push(line);
  return lines;
}

function buildTechnicalPdfBlob() {
  const pageWidth = 595;
  const pageHeight = 842;
  const marginX = 56;
  const topY = 790;
  const bottomY = 52;
  const pages = [[]];
  let y = topY;

  function newPage() { pages.push([]); y = topY; }
  function addLine(text, font, size, leading) {
    if (y < bottomY) newPage();
    pages[pages.length - 1].push({ text, font, size, x: marginX, y });
    y -= leading;
  }
  function addBlock(item) {
    const isTitle = item.type === "title";
    const isHeading = item.type === "h1";
    const font = isTitle || isHeading ? "F2" : "F1";
    const size = isTitle ? 20 : isHeading ? 13 : 9;
    const leading = isTitle ? 25 : isHeading ? 18 : 12;
    const width = isTitle ? 48 : isHeading ? 64 : 92;
    if (isHeading && y < 95) newPage();
    wrapPdfText(item.text, width).forEach((line) => addLine(line, font, size, leading));
    y -= isTitle || isHeading ? 7 : 4;
  }

  technicalDocSections().forEach(addBlock);
  const objects = [];
  objects.push("<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>");
  objects.push("<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica-Bold >>");
  const pageKids = [];
  pages.forEach((lines, index) => {
    let content = "BT\n";
    lines.forEach((line) => {
      content += "/" + line.font + " " + line.size + " Tf " + line.x + " " + line.y + " Td (" + escapePdfText(line.text) + ") Tj\n";
    });
    content += "/F1 7 Tf 56 28 Td (Pallet Check Tool - Technical Documentation) Tj\n";
    content += "/F1 7 Tf 500 28 Td (Page " + (index + 1) + ") Tj\n";
    content += "ET";
    const contentId = objects.length + 1;
    objects.push("<< /Length " + content.length + " >>\nstream\n" + content + "\nendstream");
    const pageId = objects.length + 1;
    pageKids.push(pageId + " 0 R");
    objects.push("<< /Type /Page /Parent 3 0 R /MediaBox [0 0 " + pageWidth + " " + pageHeight + "] /Resources << /Font << /F1 1 0 R /F2 2 0 R >> >> /Contents " + contentId + " 0 R >>");
  });
  objects.splice(2, 0, "<< /Type /Pages /Kids [" + pageKids.join(" ") + "] /Count " + pages.length + " >>");
  objects.push("<< /Type /Catalog /Pages 3 0 R >>");
  let pdf = "%PDF-1.4\n";
  const offsets = [0];
  objects.forEach((object, index) => {
    offsets.push(pdf.length);
    pdf += (index + 1) + " 0 obj\n" + object + "\nendobj\n";
  });
  const xref = pdf.length;
  pdf += "xref\n0 " + (objects.length + 1) + "\n0000000000 65535 f \n";
  offsets.slice(1).forEach((offset) => { pdf += String(offset).padStart(10, "0") + " 00000 n \n"; });
  pdf += "trailer << /Size " + (objects.length + 1) + " /Root " + objects.length + " 0 R >>\nstartxref\n" + xref + "\n%%EOF";
  return new Blob([pdf], { type: "application/pdf" });
}

function downloadTechnicalPdf(event) {
  if (event) event.preventDefault();
  const blob = buildTechnicalPdfBlob();
  const url = URL.createObjectURL(blob);
  const link = document.createElement("a");
  link.href = url;
  link.download = "Pallet_Check_Tool_Technical_Documentation.pdf";
  document.body.appendChild(link);
  link.click();
  link.remove();
  URL.revokeObjectURL(url);
}

function configureTechnicalPdfDownload() {
  const link = document.querySelector(".doc-download-card .doc-download-link");
  if (!link) return;
  link.setAttribute("href", "#");
  link.setAttribute("download", "Pallet_Check_Tool_Technical_Documentation.pdf");
  link.textContent = "Download technical documentation (PDF)";
  link.addEventListener("click", downloadTechnicalPdf);
}
